class Solution {
public:
    int findTheLongestBalancedSubstring(string s) {
        int maxLen = 0;
        for (int i = 0; i < s.length(); i++) {
            int zeros = 0, ones = 0;
            for (int j = i; j < s.length(); j++) {
                if (s[j] == '0') zeros++;
                else ones++;
                if (zeros == ones) maxLen = max(maxLen, (j - i + 1));
                if (ones > zeros) break;
            }
        }
        return maxLen;
    }
};
